export function findArtist(slug) {
  return ARTISTS.find((a) => a.slug === slug);
}

export function nextArtist(slug) {
  const i = ARTISTS.findIndex((a) => a.slug === slug);
  if (i === -1) return ARTISTS[0];
  return ARTISTS[(i + 1) % ARTISTS.length];
}
